function maxConsecutiveSum(arr) {
  let maxSum = -Infinity;
  let currentSum = 0;
  for (let i = 0; i < arr.length; i++) {
    if (arr[i] > 0) {
      currentSum += arr[i];
    } else {
      currentSum = 0;
    }
    maxSum = Math.max(maxSum, currentSum);
  }
  return maxSum;
}

